+<?xml version="1.0" encoding="utf-8"?>
+<androidx.constraintlayout.widget.ConstraintLayout xmlns:android="http://schemas.android.com/apk/res/android"
+    xmlns:app="http://schemas.android.com/apk/res-auto"
+    xmlns:tools="http://schemas.android.com/tools"
+    android:layout_width="wrap_content"
+    android:layout_height="wrap_content">
+
+    <View
+        android:id="@+id/centerCircle"
+        android:layout_width="1dp"
+        android:layout_height="1dp"
+        android:layout_marginStart="-32dp"
+        app:layout_constraintBottom_toBottomOf="parent"
+        app:layout_constraintStart_toStartOf="parent"
+        app:layout_constraintTop_toTopOf="parent" />
+
+    <View
+        android:id="@+id/anchorTakenButton"
+        android:layout_width="1dp"
+        android:layout_height="1dp"
+        app:layout_constraintCircle="@id/centerCircle"
+        app:layout_constraintCircleAngle="30"
+        app:layout_constraintCircleRadius="128dp"
+        tools:ignore="MissingConstraints" />
+
+    <View
+        android:id="@+id/anchorSkippedButton"
+        android:layout_width="1dp"
+        android:layout_height="1dp"
+        app:layout_constraintCircle="@id/centerCircle"
+        app:layout_constraintCircleAngle="70"
+        app:layout_constraintCircleRadius="128dp"
+        tools:ignore="MissingConstraints" />
+
+    <View
+        android:id="@+id/anchorReraiseButton"
+        android:layout_width="1dp"
+        android:layout_height="1dp"
+        app:layout_constraintCircle="@id/centerCircle"
+        app:layout_constraintCircleAngle="110"
+        app:layout_constraintCircleRadius="128dp"
+        tools:ignore="MissingConstraints" />
+
+    <View
+        android:id="@+id/anchorDeleteButton"
+        android:layout_width="1dp"
+        android:layout_height="1dp"
+        app:layout_constraintCircle="@id/centerCircle"
+        app:layout_constraintCircleAngle="150"
+        app:layout_constraintCircleRadius="128dp"
+        tools:ignore="MissingConstraints" />
+
+    <com.google.android.material.floatingactionbutton.ExtendedFloatingActionButton
+        android:id="@+id/takenButton"
+        android:layout_width="wrap_content"
+        android:layout_height="wrap_content"
+        android:clickable="true"
+        android:text="@string/taken"
+        app:icon="@drawable/check2_circle"
+        app:layout_constraintBottom_toBottomOf="@id/anchorTakenButton"
+        app:layout_constraintStart_toStartOf="@id/anchorTakenButton"
+        app:layout_constraintTop_toTopOf="@id/anchorTakenButton" />
+
+    <com.google.android.material.floatingactionbutton.ExtendedFloatingActionButton
+        android:id="@+id/skippedButton"
+        android:layout_width="wrap_content"
+        android:layout_height="wrap_content"
+        android:clickable="true"
+        android:text="@string/skipped"
+        app:icon="@drawable/x_circle"
+        app:layout_constraintBottom_toBottomOf="@id/anchorSkippedButton"
+        app:layout_constraintStart_toStartOf="@id/anchorSkippedButton"
+        app:layout_constraintTop_toTopOf="@id/anchorSkippedButton" />
+
+    <com.google.android.material.floatingactionbutton.ExtendedFloatingActionButton
+        android:id="@+id/reraiseButton"
+        android:layout_width="wrap_content"
+        android:layout_height="wrap_content"
+        android:clickable="true"
+        android:text="@string/re_raise_event"
+        app:icon="@drawable/bell"
+        app:layout_constraintBottom_toBottomOf="@id/anchorReraiseButton"
+        app:layout_constraintStart_toStartOf="@id/anchorReraiseButton"
+        app:layout_constraintTop_toTopOf="@id/anchorReraiseButton" />
+
+    <com.google.android.material.floatingactionbutton.ExtendedFloatingActionButton
+        android:id="@+id/deleteButton"
+        android:layout_width="wrap_content"
+        android:layout_height="wrap_content"
+        android:clickable="true"
+        android:text="@string/delete"
+        app:icon="@drawable/trash"
+        app:layout_constraintBottom_toBottomOf="@id/anchorDeleteButton"
+        app:layout_constraintStart_toStartOf="@id/anchorDeleteButton"
+        app:layout_constraintTop_toTopOf="@id/anchorDeleteButton" />
+
+</androidx.constraintlayout.widget.ConstraintLayout>
