+        return builder
+                .registerTypeAdapter(ReminderEvent.class, new FullDeserialize<ReminderEvent>());
+    }
+
+    public void applyBackup(List<ReminderEvent> listOfReminderEvents, MedicineRepository medicineRepository) {
